// Import necessary libraries
const axios = require('axios');

// Function to parse access token from URL fragment
function parseAccessToken() {
  const urlParams = new URLSearchParams(window.location.hash.slice(1));
  return urlParams.get('access_token');
}

// Function to store access token in session storage
function storeAccessToken(token) {
  sessionStorage.setItem('accessToken', token);
}

// Function to make API call using the access token
async function makeApiCall(url, method = 'GET', data = {}) {
  const accessToken = sessionStorage.getItem('accessToken');
  if (!accessToken) return null;
  
  try {
    const response = await axios({
      method,
      url,
      headers: { Authorization: `Bearer ${accessToken}` },
      data
    });
    
    return response.data;
  } catch (error) {
    console.error(error);
    return null;
  }
}

// Function to handle authorization flow and get access token
function authorizeFlow(clientId, redirectUri, scope) {
  const authUrl = `https://example.com/oauth/authorize?client_id=${clientId}&redirect_uri=${redirectUri}&response_type=token&scope=${scope}`;
  
  window.location.href = authUrl;
}

// Example usage:
const clientId = 'your_client_id';
const redirectUri = 'http://localhost:3000/callback';
const scope = 'read write';

authorizeFlow(clientId, redirectUri, scope);

window.addEventListener('hashchange', () => {
  const token = parseAccessToken();
  if (token) storeAccessToken(token);
});

// Make API call using the access token
makeApiCall('/api/data')
  .then(data => console.log(data))
  .catch(error => console.error(error));